(()=>{'use strict';
const APP_VERSION='Solomon DOIT Pro V2.9.0';
const T=v=>String(v??'').trim();
const N=v=>Number(String(v??'').replace(/,/g,''))||0;
const $=s=>document.querySelector(s);
let rawPayload=null,rawRows=[],meta={},patched=false,oldManualCleared=false;
function rowsOf(p){return p?.rows||p||[]}
function cleanPs(v){const parts=T(v).split(/\s+/).filter(Boolean);if(!parts.length)return'';if(parts.length===2&&parts[0]===parts[1])return parts[0];const out=[];parts.forEach(x=>{if(!out.includes(x))out.push(x)});return out.join(' ')}
function appKey(){return T(meta.id||meta.version_id||rawPayload?.version_id||meta.file_name||'active')}
function keys(prefix){const out=[];for(let i=0;i<localStorage.length;i++){const k=localStorage.key(i)||'';if(k.startsWith(prefix))out.push(k)}return out}
function rowKey(){return 'doit-insert-rows-v1:'+appKey()}
function read(k,d){try{return JSON.parse(localStorage.getItem(k)||'')||d}catch{return d}}
function write(k,v){localStorage.setItem(k,JSON.stringify(v||[]))}
function dates(){return[...new Set(rawRows.map(r=>T(r.date)).filter(Boolean))].sort()}
function selectedDates(){return[...new Set((window.DOIT_SELECTED_DATES||[]).map(T).filter(Boolean))].sort()}
function selectedPs(){return[...new Set((window.DOIT_SELECTED_PS_LIST||[]).map(cleanPs).filter(Boolean))].sort((a,b)=>a.localeCompare(b,'th'))}
function getScope(){return{dates:selectedDates(),dateKey:T(window.DOIT_SELECTED_DATE_KEY),ps:selectedPs(),psKey:T(window.DOIT_SELECTED_PS_KEY),receiver:T($('#storeSelect')?.value),brand:T($('#brandSelect')?.value),type:T($('#typeSelect')?.value),q:T($('#q')?.value).toLowerCase(),start:T($('#startDate')?.value),end:T($('#endDate')?.value),psValue:T($('#psSelect')?.value)}}
function setMsg(s){const m=$('#msg');if(m)m.textContent=s}
function lockTitle(){try{document.title=APP_VERSION}catch{}const t=document.querySelector('.title');if(t)t.textContent=APP_VERSION;const f=document.querySelector('footer');if(f&&/Solomon DOIT Pro/i.test(f.textContent||''))f.textContent=APP_VERSION}
function clearOldManualOnce(){if(oldManualCleared)return;oldManualCleared=true;keys('doit-manual-v1:').forEach(k=>localStorage.removeItem(k));document.querySelectorAll('.manualOrderRow290,.insertRow290').forEach(x=>x.remove())}
function patchLoad(){const app=window.DOIT_JSON_APP;if(!app||app.__appCoordinator290)return false;const old=app.load.bind(app);app.load=(payload,m={})=>{rawPayload=payload;meta=m||{};const arr=rowsOf(payload);if(Array.isArray(arr)&&arr.length){rawRows=arr;window.__doitRawRows290=arr;window.DOIT_ALL_DATES=dates();window.DOIT_AVAILABLE_DATES=window.DOIT_ALL_DATES}clearOldManualOnce();const res=old(payload,m);setTimeout(syncUi,0);setTimeout(syncUi,250);setTimeout(renderInsertRows,350);return res};app.__appCoordinator290=true;patched=true;return true}
function syncUi(){lockTitle();ensureInsertButton();const ds=selectedDates();const p=$('#datePreview');if(p){if(!ds.length)p.textContent='ทุกวัน';else if(ds.length===1)p.textContent=thai(ds[0]);else p.textContent=`เลือก ${ds.length} วัน: ${thai(ds[0])} - ${thai(ds[ds.length-1])}`}const pb=$('#psTickBtn289');if(pb){const ps=selectedPs();pb.textContent=ps.length?`PS: ${ps.length===1?ps[0]:ps.length+' คน'} ▼`:'PS: ทั้งหมด ▼'}window.DOIT_APP_SCOPE=getScope();setTimeout(renderInsertRows,0)}
function thai(s){const p=T(s).split('-');return p.length===3?`${p[2]}/${p[1]}/${p[0]}`:s}
function esc(s){return T(s).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]))}
function css(){if($('#insertRow290Css'))return;const st=document.createElement('style');st.id='insertRow290Css';st.textContent='.insertRow290 td{background:#fffdf3!important}.insertText290{width:100%;min-width:160px;height:34px;border:1px solid #f59e0b;border-radius:8px;padding:0 8px;font-weight:900;background:#fffbeb}.insertNum290{width:78px;height:34px;border:1px solid #f59e0b;border-radius:8px;text-align:center;font-weight:900;background:#fffbeb}.insertDel290{height:28px;border:1px solid #ef4444;background:#fef2f2;color:#b91c1c;border-radius:8px;font-weight:950;padding:0 8px}.insertTag290{display:inline-block;margin-top:3px;background:#fef3c7;color:#92400e;border:1px solid #f59e0b;border-radius:999px;padding:1px 7px;font-size:11px;font-weight:950}';document.head.appendChild(st)}
function isPickTable(){const h=[...document.querySelectorAll('#table th')].map(x=>T(x.textContent)).join('|');return /จำนวนส่งร้านนี้/.test(h)&&/จำนวนออเดอร์รวม/.test(h)}
function rowsStore(){return read(rowKey(),[])}
function saveRows(a){write(rowKey(),a)}
function rowScope(){const sc=getScope();return{start:sc.start,end:sc.end,ps:sc.psKey||sc.psValue,dateKey:sc.dateKey,psKey:sc.psKey}}
function matchScope(r,sc){if(r.dateKey&&sc.dateKey&&r.dateKey!==sc.dateKey)return false;if(!r.dateKey){if(sc.start&&T(r.start)!==sc.start)return false;if(sc.end&&T(r.end)!==sc.end)return false}if(r.psKey&&sc.psKey&&r.psKey!==sc.psKey)return false;if(!r.psKey&&sc.psValue&&T(r.ps)!==sc.psValue)return false;if(sc.q&&!([r.name,r.code,'แทรกแถว'].join(' ').toLowerCase().includes(sc.q)))return false;return true}
function visibleRows(){const sc=getScope();return rowsStore().filter(r=>matchScope(r,sc))}
function insertRow(){const a=rowsStore(),sc=rowScope();a.push({id:Date.now(),...sc,name:'',code:'',orderQty:0,unit:0,sendByStore:{},addByStore:{},pullByStore:{}});saveRows(a);renderInsertRows();setMsg('แทรกแถวแล้ว พิมพ์ชื่อสินค้าและจำนวนได้เลย');setTimeout(()=>document.querySelector('.insertRow290:last-child .insertName290')?.focus(),50)}
function ensureInsertButton(){document.querySelector('#manualAddBtn')?.remove();const a=document.querySelector('.actions');if(a&&!$('#insertRowBtn290')){const b=document.createElement('button');b.id='insertRowBtn290';b.type='button';b.className='outline';b.textContent='+ แทรกแถว';b.onclick=insertRow;a.prepend(b)}}
function numMap(r,k){return r[k]&&typeof r[k]==='object'?r[k]:{}}
function storeQty(r,k,store){return store?N(numMap(r,k)[store]):0}
function setStoreQty(r,k,store,val){if(!store)return;r[k]=numMap(r,k);r[k][store]=N(val)}
function sentTotal(r,k){const m=numMap(r,k);return Object.keys(m).reduce((s,x)=>s+N(m[x]),0)}
function remain(r){return N(r.orderQty)+sentTotal(r,'addByStore')-sentTotal(r,'sendByStore')-sentTotal(r,'pullByStore')}
function renderInsertRows(){css();document.querySelectorAll('.insertRow290,.manualOrderRow290').forEach(x=>x.remove());const tb=$('#table tbody');if(!tb||!isPickTable())return;const sc=getScope(),items=visibleRows();if(!items.length)return;const frag=document.createDocumentFragment();items.forEach((r,i)=>{const send=storeQty(r,'sendByStore',sc.receiver),add=storeQty(r,'addByStore',sc.receiver),pull=storeQty(r,'pullByStore',sc.receiver),rem=remain(r),amt=N(r.orderQty)*N(r.unit);const tr=document.createElement('tr');tr.className='insertRow290';tr.dataset.id=String(r.id);tr.innerHTML=`<td><input class="insertText290 insertName290" data-field="name" data-id="${esc(r.id)}" value="${esc(r.name)}" placeholder="พิมพ์ชื่อสินค้า"><div><span class="insertTag290">แทรกแถว</span> <input class="insertText290 insertCode290" style="width:92px;height:26px" data-field="code" data-id="${esc(r.id)}" value="${esc(r.code)}" placeholder="รหัส"></div></td><td><input class="insertNum290" data-field="orderQty" data-id="${esc(r.id)}" value="${N(r.orderQty)||''}" type="number" min="0" step="1"></td><td><input class="insertNum290" data-map="sendByStore" data-id="${esc(r.id)}" value="${send||''}" ${sc.receiver?'':'disabled'} type="number" min="0" step="1"></td><td><input class="insertNum290" data-map="addByStore" data-id="${esc(r.id)}" value="${add||''}" ${sc.receiver?'':'disabled'} type="number" min="0" step="1"></td><td><input class="insertNum290" data-map="pullByStore" data-id="${esc(r.id)}" value="${pull||''}" ${sc.receiver?'':'disabled'} type="number" min="0" step="1"></td><td class="${rem<0?'bad':'good'}">${rem}</td><td>${amt?N(amt).toFixed(2):'0.00'} <button class="insertDel290" data-id="${esc(r.id)}" type="button">ลบ</button></td>`;frag.appendChild(tr)});tb.appendChild(frag)}
function updateRow(id,field,value,map){const sc=getScope(),a=rowsStore(),r=a.find(x=>String(x.id)===String(id));if(!r)return;if(map){if(!sc.receiver)return alert('กรุณาเลือกร้านจริงก่อนกรอกจำนวนช่องนี้');setStoreQty(r,map,sc.receiver,value)}else if(field==='name'||field==='code')r[field]=T(value);else r[field]=N(value);saveRows(a);if(map||field==='orderQty')renderInsertRows();document.dispatchEvent(new CustomEvent('doit:stateChanged',{detail:{insertRow:true,id}}))}
function delRow(id){const a=rowsStore(),r=a.find(x=>String(x.id)===String(id));if(!r)return;if(!confirm('ลบแถวนี้หรือไม่'))return;saveRows(a.filter(x=>String(x.id)!==String(id)));renderInsertRows()}
function bind(){if(document.__insertRow290)return;document.__insertRow290=true;document.addEventListener('click',e=>{const d=e.target?.closest?.('.insertDel290');if(d){e.preventDefault();e.stopImmediatePropagation();delRow(d.dataset.id)}},true);document.addEventListener('input',e=>{const el=e.target?.closest?.('[data-id][data-field], [data-id][data-map]');if(el)updateRow(el.dataset.id,el.dataset.field,el.value,el.dataset.map)},true);document.addEventListener('change',e=>{if(e.target?.id==='storeSelect')setTimeout(renderInsertRows,80);const el=e.target?.closest?.('[data-id][data-field], [data-id][data-map]');if(el)updateRow(el.dataset.id,el.dataset.field,el.value,el.dataset.map)},true);['doit:scopeRendered','doit:selectedDatesChanged','doit:psChanged'].forEach(ev=>document.addEventListener(ev,()=>setTimeout(renderInsertRows,80)))}
function health(){return{version:APP_VERSION,patched,appKey:appKey(),rows:rawRows.length,scope:getScope(),insertRows:visibleRows().length,rowKey:rowKey(),scripts:[...document.scripts].map(s=>s.getAttribute('src')).filter(Boolean).filter(s=>/doit|coordinator|fix|owner|drawer/i.test(s))}}
function expose(){window.DOIT_APP_COORDINATOR={version:APP_VERSION,getScope,health,rowKey,renderInsertRows,rerender:()=>window.DOIT_JSON_APP?.rerender?.()}}
function boot(){clearOldManualOnce();patchLoad();bind();expose();syncUi();let n=0;const tick=()=>{patchLoad();bind();expose();syncUi();renderInsertRows();if(++n<10)setTimeout(tick,600)};setTimeout(tick,300)}
document.addEventListener('DOMContentLoaded',boot);if(document.readyState!=='loading')boot();
})();